-- First update all existing values to 'demo'
UPDATE savedPortfolios SET portfolioType = 'demo' WHERE portfolioType IS NULL OR portfolioType NOT IN ('demo', 'live');

-- Now modify the column
ALTER TABLE savedPortfolios 
MODIFY COLUMN portfolioType ENUM('demo', 'live') NOT NULL DEFAULT 'demo';

-- Add investmentAmount column
ALTER TABLE savedPortfolios 
ADD COLUMN investmentAmount VARCHAR(50) NOT NULL DEFAULT '0';

